18→
19→import android.content.SharedPreferences
20→import android.view.KeyEvent
21→import com.ichi2.anki.AnkiDroidApp
22→import com.ichi2.anki.cardviewer.ViewerCommand
23→import com.ichi2.anki.preferences.sharedPrefs
