 38→/**
 39→ * The previewer intent must supply an array of cards to show and the index in the list from where
 40→ * to begin showing them. Special rules are applied if the list size is 1 (i.e., no scrolling
 41→ * buttons will be shown).
 42→ */
 43→
 44→class Previewer : AbstractFlashcardViewer() {
 45→    private lateinit var mCardList: LongArray
 46→    private var mIndex = 0
 47→    private var mShowingAnswer = false
 48→    private lateinit var mProgressSeekBar: SeekBar
 49→    private lateinit var mProgressText: TextView
 50→
 51→    /** Communication with Browser  */
 52→    private var mReloadRequired = false
 53→    private var mNoteChanged = false
 54→    private var previewLayout: PreviewLayout? = null
 55→    override fun onCreate(savedInstanceState: Bundle?) {
 56→        if (showedActivityFailedScreen(savedInstanceState)) {
 57→            return
 58→        }
 59→        super.onCreate(savedInstanceState)
 60→        mCardList = intent.getLongArrayExtra("cardList")!!
 61→        mIndex = intent.getIntExtra("index", -1)
 62→        if (savedInstanceState != null) {
 63→            mIndex = savedInstanceState.getInt("index", mIndex)
 64→            mShowingAnswer = savedInstanceState.getBoolean("showingAnswer", mShowingAnswer)
 65→            mReloadRequired = savedInstanceState.getBoolean("reloadRequired")
 66→            mNoteChanged = savedInstanceState.getBoolean("noteChanged")
 67→        }
 68→        if (mCardList.isEmpty() || mIndex < 0 || mIndex > mCardList.size - 1) {
 69→            Timber.e("Previewer started with empty card list or invalid index")
 70→            finishWithoutAnimation()
 71→            return
 72→        }
 73→        showBackIcon()
 74→        // Ensure navigation drawer can't be opened. Various actions in the drawer cause crashes.
 75→        disableDrawerSwipe()
 76→        startLoadingCollection()
 77→        initPreviewProgress()
 78→    }
 79→
 80→    private fun initPreviewProgress() {
 81→        mProgressSeekBar = findViewById(R.id.preview_progress_seek_bar)
 82→        mProgressText = findViewById(R.id.preview_progress_text)
 83→        val progressLayout = findViewById<LinearLayout>(R.id.preview_progress_layout)
 84→
 85→        // Show layout only when the cardList is bigger than 1
 86→        if (mCardList.size > 1) {
 87→            progressLayout.visibility = View.VISIBLE
 88→            mProgressSeekBar.max = mCardList.size - 1
 89→            setSeekBarListener()
 90→            updateProgress()
 91→        }
 92→    }
 93→
 94→    private fun setSeekBarListener() {
 95→        mProgressSeekBar.setOnSeekBarChangeListener(object : OnSeekBarChangeListener {
 96→            override fun onProgressChanged(seekBar: SeekBar, progress: Int, fromUser: Boolean) {
 97→                if (fromUser) {
 98→                    mIndex = progress
 99→                    updateProgress()
100→                    currentCard = col.getCard(mCardList[mIndex])
101→                    displayCardQuestion()
102→                }
103→            }
104→
105→            override fun onStartTrackingTouch(seekBar: SeekBar) {
106→                // Mandatory override, but unused
107→            }
108→
109→            override fun onStopTrackingTouch(seekBar: SeekBar) {
110→                if (mIndex >= 0 && mIndex < mCardList.size) {
111→                    currentCard = col.getCard(mCardList[mIndex])
112→                    displayCardQuestion()
113→                }
114→            }
115→        })
116→    }
117→
118→    override fun onCollectionLoaded(col: Collection) {
119→        super.onCollectionLoaded(col)
120→        currentCard = col.getCard(mCardList[mIndex])
121→        displayCardQuestion()
122→        if (mShowingAnswer) {
123→            displayCardAnswer()
124→        }
125→        showBackIcon()
126→    }
127→
128→    /** Given a new collection of card Ids, find the 'best' valid card given the current collection
129→     * We define the best as searching to the left, then searching to the right of the current element
130→     * This occurs as many cards can be deleted when editing a note (from the Card Template Editor)  */
131→    private fun getNextIndex(newCardList: List<Long>): Int {
132→        val validIndices = HashSet(newCardList)
133→        for (i in mIndex downTo 0) {
134→            if (validIndices.contains(mCardList[i])) {
135→                return newCardList.indexOf(mCardList[i])
136→            }
137→        }
138→        for (i in mIndex + 1 until validIndices.size) {
139→            if (validIndices.contains(mCardList[i])) {
140→                return newCardList.indexOf(mCardList[i])
141→            }
142→        }
143→        throw IllegalStateException("newCardList was empty")
144→    }
145→
146→    override fun initLayout() {
147→        super.initLayout()
148→        topBarLayout!!.visibility = View.GONE
149→        findViewById<View>(R.id.answer_options_layout).visibility = View.GONE
150→        findViewById<View>(R.id.bottom_area_layout).visibility = View.VISIBLE
151→        previewLayout = PreviewLayout.createAndDisplay(this, mToggleAnswerHandler)
152→        previewLayout!!.setOnNextCard { changePreviewedCard(true) }
153→        previewLayout!!.setOnPreviousCard { changePreviewedCard(false) }
154→    }
155→
156→    override fun onOptionsItemSelected(item: MenuItem): Boolean {
157→        if (item.itemId == R.id.action_edit) {
158→            editCard()
159→            return true
160→        }
161→        return super.onOptionsItemSelected(item)
162→    }
163→
164→    override fun onBackPressed() {
165→        setResult(RESULT_OK, resultIntent)
166→        super.onBackPressed()
167→    }
168→
169→    override fun onNavigationPressed() {
170→        setResult(RESULT_OK, resultIntent)
171→        super.onNavigationPressed()
172→    }
173→
174→    override fun onCreateOptionsMenu(menu: Menu): Boolean {
175→        menuInflater.inflate(R.menu.previewer, menu)
176→        return super.onCreateOptionsMenu(menu)
177→    }
178→
179→    override fun onSaveInstanceState(outState: Bundle) {
180→        outState.putLongArray("cardList", mCardList)
181→        outState.putInt("index", mIndex)
182→        outState.putBoolean("showingAnswer", mShowingAnswer)
183→        outState.putBoolean("reloadRequired", mReloadRequired)
184→        outState.putBoolean("noteChanged", mNoteChanged)
185→        super.onSaveInstanceState(outState)
186→    }
187→
188→    override fun displayCardQuestion() {
189→        super.displayCardQuestion()
190→        mShowingAnswer = false
191→        updateButtonsState()
192→    }
193→
194→    // Called via mFlipCardListener in parent class when answer button pressed
195→    @VisibleForTesting(otherwise = VisibleForTesting.PROTECTED)
196→    override fun displayCardAnswer() {
197→        super.displayCardAnswer()
198→        mShowingAnswer = true
199→        updateButtonsState()
200→    }
201→
202→    override fun hideEaseButtons() {
203→        /* do nothing */
204→    }
205→
206→    override fun displayAnswerBottomBar() {
207→        /* do nothing */
208→    }
209→
210→    override fun executeCommand(which: ViewerCommand, fromGesture: Gesture?): Boolean {
211→        /* do nothing */
212→        return false
213→    }
214→
215→    override fun performReload() {
216→        mReloadRequired = true
217→        val newCardList = col.filterToValidCards(mCardList)
218→        if (newCardList.isEmpty()) {
219→            finishWithoutAnimation()
220→            return
221→        }
222→        mIndex = getNextIndex(newCardList)
223→        mCardList = newCardList.toLongArray()
224→        currentCard = col.getCard(mCardList[mIndex])
225→        displayCardQuestion()
226→    }
227→
228→    override fun onEditedNoteChanged() {
229→        super.onEditedNoteChanged()
230→        mNoteChanged = true
231→    }
232→
233→    @VisibleForTesting(otherwise = VisibleForTesting.PRIVATE)
234→    internal fun changePreviewedCard(nextCard: Boolean) {
235→        mIndex = if (nextCard) mIndex + 1 else mIndex - 1
236→        currentCard = col.getCard(mCardList[mIndex])
237→        displayCardQuestion()
238→        updateProgress()
239→    }
240→
241→    private val mToggleAnswerHandler = View.OnClickListener {
242→        if (mShowingAnswer) {
243→            displayCardQuestion()
244→        } else {
245→            displayCardAnswer()
246→        }
247→    }
248→
249→    private fun updateButtonsState() {
250→        previewLayout!!.setShowingAnswer(mShowingAnswer)
251→
252→        // If we are in single-card mode, we show the "Show Answer" button on the question side
253→        // and hide navigation buttons.
254→        if (mCardList.size == 1) {
255→            previewLayout!!.hideNavigationButtons()
256→            return
257→        }
258→        previewLayout!!.setPrevButtonEnabled(mIndex > 0)
259→        previewLayout!!.setNextButtonEnabled(mIndex < mCardList.size - 1)
260→    }
261→
262→    private fun updateProgress() {
263→        if (mProgressSeekBar.progress != mIndex) {
264→            mProgressSeekBar.progress = mIndex
265→        }
266→        val progress = getString(R.string.preview_progress_bar_text, mIndex + 1, mCardList.size)
267→        mProgressText.text = progress
268→    }
269→
270→    private val resultIntent: Intent
271→        get() {
272→            val intent = Intent()
273→            intent.putExtra("reloadRequired", mReloadRequired)
274→            intent.putExtra("noteChanged", mNoteChanged)
275→            return intent
276→        }
277→
278→    companion object {
279→        @CheckResult
280→        fun getPreviewIntent(context: Context?, index: Int, cardList: LongArray?): Intent {
281→            val intent = Intent(context, Previewer::class.java)
282→            intent.putExtra("index", index)
283→            intent.putExtra("cardList", cardList)
284→            return intent
285→        }
286→    }
287→}
