29→/** Accepts peripheral input, mapping via various keybinding strategies,
30→ * and converting them to commands for the Reviewer.  */
31→class PeripheralKeymap(reviewerUi: ReviewerUi, commandProcessor: ViewerCommand.CommandProcessor) {
32→    private val mKeyMap: KeyMap
33→    private var mHasSetup = false
34→    fun setup() {
35→        val preferences = AnkiDroidApp.instance.sharedPrefs()
36→        setup(preferences)
37→    }
38→
39→    fun setup(preferences: SharedPreferences) {
40→        for (command in ViewerCommand.values()) {
41→            add(command, preferences)
42→        }
43→        mHasSetup = true
44→    }
45→
46→    private fun add(command: ViewerCommand, preferences: SharedPreferences) {
47→        val bindings: MutableList<MappableBinding> = fromPreference(preferences, command)
48→        for (b in bindings) {
49→            if (!b.isKey) {
50→                continue
51→            }
52→            mKeyMap[b] = command
53→        }
54→    }
55→
56→    fun onKeyDown(keyCode: Int, event: KeyEvent): Boolean {
57→        return if (!mHasSetup || event.repeatCount > 0) {
58→            false
59→        } else {
60→            mKeyMap.onKeyUp(keyCode, event)
61→        }
62→    }
63→
64→    @Suppress("UNUSED_PARAMETER")
65→    fun onKeyUp(keyCode: Int, event: KeyEvent?): Boolean {
66→        return false
67→    }
68→
69→    class KeyMap(private val processor: ViewerCommand.CommandProcessor, private val reviewerUI: ReviewerUi) {
70→        val mBindingMap = HashMap<MappableBinding, ViewerCommand>()
71→
72→        @Suppress("UNUSED_PARAMETER")
73→        fun onKeyUp(keyCode: Int, event: KeyEvent?): Boolean {
74→            var ret = false
75→            val bindings = key(event!!)
76→            val side = fromAnswer(reviewerUI.isDisplayingAnswer)
77→            for (b in bindings) {
78→                val binding = MappableBinding(b, MappableBinding.Screen.Reviewer(side))
79→                val command = mBindingMap[binding] ?: continue
80→                ret = ret or processor.executeCommand(command, fromGesture = null)
81→            }
82→            return ret
83→        }
84→
85→        operator fun set(key: MappableBinding, value: ViewerCommand) {
86→            mBindingMap[key] = value
87→        }
88→
89→        operator fun get(key: MappableBinding): ViewerCommand? {
90→            return mBindingMap[key]
91→        }
92→    }
93→
94→    init {
95→        mKeyMap = KeyMap(commandProcessor, reviewerUi)
96→    }
97→}
