371→        internal class UpgradeAppLocale : PreferenceUpgrade(10) {
372→            override fun upgrade(preferences: SharedPreferences) {
373→                fun getLocale(localeCode: String): Locale {
374→                    // Language separators are '_' or '-' at different times in display/resource fetch
375→                    val locale: Locale = if (localeCode.contains("_") || localeCode.contains("-")) {
376→                        try {
377→                            val localeParts = localeCode.split("[_-]".toRegex(), 2).toTypedArray()
378→                            Locale(localeParts[0], localeParts[1])
379→                        } catch (e: ArrayIndexOutOfBoundsException) {
380→                            Timber.w(e, "getLocale variant split fail, using code '%s' raw.", localeCode)
381→                            Locale(localeCode)
382→                        }
383→                    } else {
384→                        Locale(localeCode) // guaranteed to be non null
385→                    }
386→                    return locale
387→                }
388→                // 1. upgrade value from `locale.toString()` to `locale.toLanguageTag()`,
389→                // because the new API uses language tags
390→                val languagePrefValue = preferences.getString("language", "")!!
391→                val languageTag = if (languagePrefValue.isNotEmpty()) {
392→                    getLocale(languagePrefValue).toLanguageTag()
393→                } else {
394→                    null
395→                }
396→                preferences.edit {
397→                    putString("language", languageTag ?: "")
398→                }
399→                // 2. Set the locale with the new AndroidX API
400→                val localeList = LocaleListCompat.forLanguageTags(languageTag)
401→                AppCompatDelegate.setApplicationLocales(localeList)
402→            }
403→        }
404→    }
